import { useState, useEffect, useRef } from "react";
import "../styles/Stats.css";

export default function Stats() {
  const stats = [
    { label: "Projects Completed", value: 500 },
    { label: "Clients Served", value: 100 },
    { label: "Years of Experience", value: 2 },
    { label: "Team Members", value: 10 },
  ];

  const [animatedValues, setAnimatedValues] = useState(stats.map(() => 0));
  const [inView, setInView] = useState(false);
  const statsSectionRef = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          setInView(true);
        }
      });
    }, {
      threshold: 0.5, // Trigger when 50% of the section is visible
    });

    const currentRef = statsSectionRef.current; // Copy ref to a variable

    if (currentRef) {
      observer.observe(currentRef);
    }

    return () => {
      if (currentRef) {
        observer.unobserve(currentRef); // Use the copied ref variable here
      }
    };
  }, []); // Empty dependency array as before

  useEffect(() => {
    if (!inView) return;

    const interval = setInterval(() => {
      setAnimatedValues((prevValues) =>
        prevValues.map((value, index) => {
          const target = stats[index].value;
          // Gradually increase the number
          if (value < target) {
            return Math.min(value + Math.ceil(target / 100), target);
          }
          return value;
        })
      );
    }, 100); // Interval to slow down the number increment

    return () => clearInterval(interval);
  }, [inView]); // Only depend on `inView` since `stats` is static

  return (
    <section ref={statsSectionRef} className="stats-section">
      {stats.map((stat, index) => (
        <div key={index} className="stat-item">
          <div className="orbit-path">
            <div
              className="orbiting-line"
              style={{
                transform: `rotate(${(animatedValues[index] / stat.value) * 360}deg)`,
              }}
            />
          </div>
          <h4>{animatedValues[index]}+</h4>
          <p>{stat.label}</p>
        </div>
      ))}
    </section>
  );
}
